import{m as t,aU as a,z as r,M as l}from"./chunks/framework.LN92DB6A.js";const i=JSON.parse('{"title":"广州疫苗接种攻略：儿童疫苗、HPV预约、流感疫苗怎么打","description":"在广州打疫苗，免费和自费怎么选？HPV怎么预约？本文整理儿童疫苗时间表、成人疫苗推荐和预约全流程。","frontmatter":{"title":"广州疫苗接种攻略：儿童疫苗、HPV预约、流感疫苗怎么打","tags":["广州","疫苗","HPV疫苗","儿童疫苗","流感疫苗","粤苗"],"categories":["医疗"],"date":"2026-06-05T00:00:00.000Z","description":"在广州打疫苗，免费和自费怎么选？HPV怎么预约？本文整理儿童疫苗时间表、成人疫苗推荐和预约全流程。","head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/posts/2026/vaccine-guide"}]]},"headers":[],"relativePath":"posts/2026/vaccine-guide.md","filePath":"posts/2026/vaccine-guide.md","lastUpdated":1779868425000}');const o=t({name:"posts/2026/vaccine-guide.md"},[["render",function(t,i,o,d,s,e){return a(),r("div",null,[...i[0]||(i[0]=[l('<p>疫苗是预防疾病最经济有效的方式。在广州打疫苗，免费的国家免疫规划疫苗必须打，自费的二类疫苗也建议打。但很多人搞不清哪些该打、怎么预约、去哪打。</p><p>这篇文章帮你理清楚：儿童疫苗时间表、成人推荐疫苗、HPV怎么预约。</p><h2 id="一类疫苗-vs-二类疫苗" tabindex="-1">一类疫苗 vs 二类疫苗 <a class="header-anchor" href="#一类疫苗-vs-二类疫苗" aria-label="Permalink to &quot;一类疫苗 vs 二类疫苗&quot;">​</a></h2><div class="table-container"><table><thead><tr><th>对比项</th><th>一类疫苗（免费）</th><th>二类疫苗（自费）</th></tr></thead><tbody><tr><td>费用</td><td>国家免费</td><td>自费</td></tr><tr><td>是否必须打</td><td>必须</td><td>自愿</td></tr><tr><td>常见种类</td><td>乙肝、卡介苗、百白破、脊灰、麻腮风等</td><td>HPV、流感、水痘、肺炎、轮状病毒等</td></tr><tr><td>入学查验</td><td>需要</td><td>部分需要</td></tr></tbody></table></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>二类疫苗虽然自费，但不代表不重要。比如水痘、流感、手足口病疫苗，都是孩子容易得的病，建议在经济允许的情况下尽量接种。</p></div><h2 id="儿童疫苗接种时间表" tabindex="-1">儿童疫苗接种时间表 <a class="header-anchor" href="#儿童疫苗接种时间表" aria-label="Permalink to &quot;儿童疫苗接种时间表&quot;">​</a></h2><p>以下是国家免疫规划疫苗的接种时间（0-6岁）：</p><div class="table-container"><table><thead><tr><th>月龄/年龄</th><th>疫苗</th></tr></thead><tbody><tr><td>出生</td><td>乙肝疫苗（第1针）、卡介苗</td></tr><tr><td>1月龄</td><td>乙肝疫苗（第2针）</td></tr><tr><td>2月龄</td><td>脊灰疫苗（第1剂）</td></tr><tr><td>3月龄</td><td>脊灰疫苗（第2剂）、百白破疫苗（第1针）</td></tr><tr><td>4月龄</td><td>脊灰疫苗（第3剂）、百白破疫苗（第2针）</td></tr><tr><td>5月龄</td><td>百白破疫苗（第3针）</td></tr><tr><td>6月龄</td><td>乙肝疫苗（第3针）、A群流脑疫苗（第1针）</td></tr><tr><td>8月龄</td><td>麻腮风疫苗（第1针）、乙脑减毒活疫苗（第1针）</td></tr><tr><td>9月龄</td><td>A群流脑疫苗（第2针）</td></tr><tr><td>18月龄</td><td>麻腮风疫苗（第2针）、百白破疫苗（第4针）、甲肝减毒活疫苗</td></tr><tr><td>2岁</td><td>乙脑减毒活疫苗（第2针）</td></tr><tr><td>3岁</td><td>A群C群流脑疫苗（第1针）</td></tr><tr><td>4岁</td><td>脊灰疫苗（第4剂）</td></tr><tr><td>6岁</td><td>百白破疫苗（第5针）、A群C群流脑疫苗（第2针）</td></tr></tbody></table></div><p>以上为一类免费疫苗，具体时间以接种单位通知为准。</p><h2 id="成人推荐疫苗" tabindex="-1">成人推荐疫苗 <a class="header-anchor" href="#成人推荐疫苗" aria-label="Permalink to &quot;成人推荐疫苗&quot;">​</a></h2><p>大人也需要打疫苗，以下几种值得关注：</p><h3 id="hpv疫苗" tabindex="-1">HPV疫苗 <a class="header-anchor" href="#hpv疫苗" aria-label="Permalink to &quot;HPV疫苗&quot;">​</a></h3><ul><li><strong>二价</strong>：预防HPV16、18型（约70%宫颈癌），9-45岁女性</li><li><strong>四价</strong>：预防HPV6、11、16、18型，20-45岁女性</li><li><strong>九价</strong>：预防9种HPV型别（约90%宫颈癌），9-45岁女性</li></ul><p>越早打越好，最好在首次性行为之前接种。</p><h3 id="流感疫苗" tabindex="-1">流感疫苗 <a class="header-anchor" href="#流感疫苗" aria-label="Permalink to &quot;流感疫苗&quot;">​</a></h3><ul><li>每年<strong>9-11月</strong>接种最佳（流感季前）</li><li>6月龄以上所有人都建议接种</li><li>尤其推荐：老人、儿童、孕妇、慢性病患者</li></ul><h3 id="带状疱疹疫苗" tabindex="-1">带状疱疹疫苗 <a class="header-anchor" href="#带状疱疹疫苗" aria-label="Permalink to &quot;带状疱疹疫苗&quot;">​</a></h3><ul><li>50岁以上成人建议接种</li><li>得过带状疱疹的人也建议接种（防止复发）</li></ul><h3 id="乙肝疫苗" tabindex="-1">乙肝疫苗 <a class="header-anchor" href="#乙肝疫苗" aria-label="Permalink to &quot;乙肝疫苗&quot;">​</a></h3><ul><li>如果乙肝表面抗体阴性，建议补种</li><li>可以到社区卫生服务中心查抗体再决定</li></ul><h2 id="hpv疫苗预约攻略" tabindex="-1">HPV疫苗预约攻略 <a class="header-anchor" href="#hpv疫苗预约攻略" aria-label="Permalink to &quot;HPV疫苗预约攻略&quot;">​</a></h2><p>HPV疫苗长期供不应求，九价尤其紧张。以下是广州的预约渠道：</p><h3 id="预约渠道" tabindex="-1">预约渠道 <a class="header-anchor" href="#预约渠道" aria-label="Permalink to &quot;预约渠道&quot;">​</a></h3><ol><li><strong>&quot;粤苗&quot;APP/小程序</strong>：广州官方疫苗预约平台，大部分社区卫生服务中心的号源在这里</li><li><strong>&quot;广州疾控&quot;公众号</strong>：不定期发布疫苗到货信息</li><li><strong>各社区卫生服务中心公众号</strong>：部分中心有自己的预约入口</li><li><strong>支付宝/微信&quot;医疗健康&quot;</strong>：部分私立机构的号源</li></ol><h3 id="预约技巧" tabindex="-1">预约技巧 <a class="header-anchor" href="#预约技巧" aria-label="Permalink to &quot;预约技巧&quot;">​</a></h3><ul><li><strong>放号时间</strong>：各社区中心放号时间不同，提前关注公众号了解</li><li><strong>提前注册</strong>：在&quot;粤苗&quot;上提前注册好个人信息，放号时直接抢</li><li><strong>不限户籍</strong>：HPV疫苗不限户籍，有号就能约</li><li><strong>不限居住地</strong>：可以跨区预约，哪个区有号就去哪个区打</li></ul><h3 id="九价-vs-四价-vs-二价怎么选" tabindex="-1">九价 vs 四价 vs 二价怎么选 <a class="header-anchor" href="#九价-vs-四价-vs-二价怎么选" aria-label="Permalink to &quot;九价 vs 四价 vs 二价怎么选&quot;">​</a></h3><ul><li>能约到<strong>九价</strong>就打九价</li><li>九价约不到，<strong>四价</strong>也很好</li><li>四价也约不到，<strong>二价</strong>照样能防70%的宫颈癌</li><li>不要为了等九价而一直不打，越早保护越好</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>HPV疫苗越早打越好。不要为了等九价而拖延，能约到什么就先打什么。保护效果远比疫苗&quot;档次&quot;重要。</p></div><h2 id="接种流程" tabindex="-1">接种流程 <a class="header-anchor" href="#接种流程" aria-label="Permalink to &quot;接种流程&quot;">​</a></h2><p>不管是儿童还是成人，接种流程都差不多：</p><ol><li><strong>预约</strong>：通过&quot;粤苗&quot;APP或社区卫生服务中心公众号预约</li><li><strong>登记</strong>：到接种点后出示预约信息、身份证（儿童带预防接种证）</li><li><strong>接种</strong>：由医护人员接种</li><li><strong>留观</strong>：接种后在现场<strong>留观30分钟</strong>，确认无异常后离开</li></ol><h3 id="接种前注意" tabindex="-1">接种前注意 <a class="header-anchor" href="#接种前注意" aria-label="Permalink to &quot;接种前注意&quot;">​</a></h3><ul><li>感冒、发烧、腹泻期间<strong>不能接种</strong></li><li>对疫苗成分过敏的不能接种</li><li>接种前如实告知医生身体状况和过敏史</li></ul><h3 id="接种后注意" tabindex="-1">接种后注意 <a class="header-anchor" href="#接种后注意" aria-label="Permalink to &quot;接种后注意&quot;">​</a></h3><ul><li>接种部位24小时内不要沾水</li><li>可能出现低热、局部红肿，一般1-2天自行缓解</li><li>严重不适及时就医</li></ul><h2 id="跨区-异地接种" tabindex="-1">跨区/异地接种 <a class="header-anchor" href="#跨区-异地接种" aria-label="Permalink to &quot;跨区/异地接种&quot;">​</a></h2><p>在广州接种外地疫苗本上的疫苗，或者外地来广州接种，都可以衔接：</p><ul><li>带上<strong>预防接种证</strong>到居住地附近的社区卫生服务中心</li><li>工作人员会将之前的接种记录录入系统</li><li>后续按广州的接种安排继续接种</li></ul><p>接种记录可以在&quot;粤苗&quot;APP上查询。</p><h2 id="避坑提醒" tabindex="-1">避坑提醒 <a class="header-anchor" href="#避坑提醒" aria-label="Permalink to &quot;避坑提醒&quot;">​</a></h2><ul><li><strong>别错过儿童疫苗的最佳接种时间</strong>：有月龄限制，错过可能需要补种或延迟入园入学</li><li><strong>HPV疫苗越早打越好</strong>：不要纠结价数，能约到就打</li><li><strong>接种后留观30分钟不能省</strong>：万一有过敏反应，在接种点处理最安全</li><li><strong>感冒发烧期间不能接种</strong>：等好了再去，不影响后续接种计划</li><li><strong>二类疫苗别因省钱而不打</strong>：水痘、流感、手足口等疫苗能有效预防常见传染病</li><li><strong>接种证要保管好</strong>：入幼儿园和小学都要查验，丢了补办麻烦</li><li><strong>预约了就按时去</strong>：爽约可能影响后续预约信用</li></ul><p>打疫苗是保护自己和家人最简单有效的方式。按时间表接种、及时预约HPV、每年打流感疫苗，养成习惯就好。</p>',43)])])}]]);export{i as __pageData,o as default};
